import React, { useMemo } from 'react';
import { makeStyles } from '@material-ui/core/styles';
import { useIntl } from 'gatsby-plugin-intl';
import { graphql } from 'gatsby';
import { GridList, GridListTile, GridListTileBar, Typography } from '@material-ui/core';
import Image from 'gatsby-image';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import SEO from '../components/SEO';
import Layout from '../components/Layout';
import Link from '../components/Link';

const useStyles = makeStyles((theme) => ({
    projectsText: {
        marginTop: '15px',
    },
    projectsListWrapper: {
        marginLeft: '0',
        padding: '15px 25px 15px 0',
    },
    projectsWrapper: {
        margin: '15px 5px',
        display: 'flex',
        flexWrap: 'wrap',
        justifyContent: 'space-around',
        overflow: 'hidden',
        // backgroundColor: theme.palette.background.paper,
    },
    projectImage: {
        width: '100% !important',
        minWidth: '500px',
    },
    gridList: {
        // width: 500,
        // height: 450,
    },
    gridListItem: {
        [theme.breakpoints.down('xs')]: {
            width: '100% !important',
        },
        '&:last-child:nth-child(odd)': {
            width: '100% !important',
        },
    },
}));

const PhotosPage = ({ location, data, pageContext }) => {
    const intl = useIntl();
    const classes = useStyles();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    const photosData = [
        // {
        //     img: data.e32012,
        //     title: 'e3_2012_photos.title',
        //     path: '/photos/e3-2012',
        //     location: 'Los Angeles',
        //     marginTop: '-270px',
        // },
        // {
        //     img: data.e32013,
        //     title: 'e3_2013_photos.title',
        //     path: '/photos/e3-2013',
        //     location: 'Los Angeles',
        //     marginTop: '-185px',
        // },
        // {
        //     img: data.e32014,
        //     title: 'e3_2014_photos.title',
        //     path: '/photos/e3-2014',
        //     location: 'Los Angeles',
        //     marginTop: '-160px',
        // },
        // {
        //     img: data.e32015,
        //     title: 'e3_2015_photos.title',
        //     path: '/photos/e3-2015',
        //     location: 'Los Angeles',
        //     marginTop: '-90px',
        // },
        {
            img: data.e32017,
            title: 'e3_2017_photos.title',
            path: '/photos/e3-2017',
            location: 'Los Angeles',
            marginTop: '-270px',
        },
        {
            img: data.e32019,
            title: 'e3_2019_photos.title',
            path: '/photos/e3-2019',
            location: 'Los Angeles',
            marginTop: '-40px',
        },
        {
            img: data.gamescom2019,
            title: 'gamescom_2019_photos.title',
            path: '/photos/gamescom-2019',
            location: 'Cologne',
            marginTop: '-300px',
        },
        {
            img: data.sanFrancisco2019,
            title: 'san_francisco_2019_photos.title',
            path: '/photos/san-francisco-2019',
            location: 'San Francisco',
            marginTop: '-440px',
        },
    ];

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'photos' })}
                ogImage={data.e32019.childImageSharp?.fixed?.src}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.personal_projects' }),
                    intl.formatMessage({ id: 'seo_keywords.games' }),
                    intl.formatMessage({ id: 'seo_keywords.development' }),
                    intl.formatMessage({ id: 'seo_keywords.es6' }),
                    intl.formatMessage({ id: 'seo_keywords.javascript' }),
                    intl.formatMessage({ id: 'seo_keywords.developer' }),
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <Typography
                className={classes.projectsText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: 'photos' })}
            </Typography>
            <div className={classes.projectsWrapper}>
                <GridList
                    cellHeight={180}
                    className={classes.gridList}
                >
                    {photosData.map((pagePreviewData) => (
                        <GridListTile
                            key={pagePreviewData.title}
                            className={classes.gridListItem}
                        >
                            <Link to={pagePreviewData.path}>
                                <Image
                                    className={classes.projectImage}
                                    style={{
                                        marginTop: pagePreviewData.marginTop,
                                    }}
                                    fixed={{
                                        ...pagePreviewData.img.childImageSharp.fixed,
                                        aspectRatio: 1,
                                    }}
                                />
                            </Link>
                            <GridListTileBar
                                title={intl.formatMessage({ id: pagePreviewData.title })}
                                subtitle={<span>{pagePreviewData.location}</span>}
                            />
                        </GridListTile>
                    ))}
                </GridList>
            </div>
        </Layout>
    );
};

export default PhotosPage;

export const pageQuery = graphql`
    query {
        site {
            siteMetadata {
                siteUrl
            }
        }
#        e32012: file(
#            absolutePath: { regex: "/e3-2012.jpg/" }
#        ) {
#            childImageSharp {
#                fixed(width: 1000, height: 900) {
#                    ...GatsbyImageSharpFixed
#                }
#            }
#        }
#        e32013: file(
#            absolutePath: { regex: "/e3-2013.jpg/" }
#        ) {
#            childImageSharp {
#                fixed(width: 1000, height: 900) {
#                    ...GatsbyImageSharpFixed
#                }
#            }
#        }
#        e32014: file(
#            absolutePath: { regex: "/e3-2014.jpg/" }
#        ) {
#            childImageSharp {
#                fixed(width: 1000, height: 900) {
#                    ...GatsbyImageSharpFixed
#                }
#            }
#        }
#        e32015: file(
#            absolutePath: { regex: "/e3-2015.jpg/" }
#        ) {
#            childImageSharp {
#                fixed(width: 1000, height: 900) {
#                    ...GatsbyImageSharpFixed
#                }
#            }
#        }
        e32017: file(
            absolutePath: { regex: "/e3-2017.jpg/" }
        ) {
            childImageSharp {
                fixed(width: 1000, height: 900) {
                    ...GatsbyImageSharpFixed
                }
            }
        }
        e32019: file(
            absolutePath: { regex: "/e3-2019.jpg/" }
        ) {
            childImageSharp {
                fixed(width: 1000, height: 900) {
                    ...GatsbyImageSharpFixed
                }
            }
        }
        gamescom2019: file(
            absolutePath: { regex: "/gamescom-2019.jpg/" }
        ) {
            childImageSharp {
                fixed(width: 1000, height: 900) {
                    ...GatsbyImageSharpFixed
                }
            }
        }
        sanFrancisco2019: file(
            absolutePath: { regex: "/san-francisco-2019.jpg/" }
        ) {
            childImageSharp {
                fixed(width: 1000, height: 900) {
                    ...GatsbyImageSharpFixed
                }
            }
        }
    }
`;
